echo === Python site-packages khy ===
dir /b D:\Python312\Lib\site-packages\khy*.* 2>NUL
echo === khy dist-info ===
dir /b D:\Python312\Lib\site-packages\khy_os* 2>NUL || echo (none)
echo === also check egg-info ===
dir /b D:\Python312\Lib\site-packages\khy_os-*.dist-info 2>NUL || echo (no dist-info)
echo === check for __pycache__ ===
dir /s /b D:\Python312\Lib\site-packages\khy\__pycache__ 2>NUL || echo (no pycache)
echo === .khy home dir contents ===
dir /b C:\Users\25789\.khy 2>NUL || echo (no .khy dir)
echo === any khy *backup* or *old* ===
dir /s /b C:\Users\25789\.khy\*old* C:\Users\25789\.khy\*bak* C:\Users\25789\.khy\*prev* C:\Users\25789\.khy\*v1* 2>NUL || echo (no backup/old files)
echo === any other khy bin ===
where khy* 2>NUL || echo "no other khy in PATH"

echo === site-packages khy entries ===
dir D:\Python312\Lib\site-packages\ 2>NUL | findstr /i khy
echo === pip show khy-os ===
pip show khy-os 2>NUL
echo === pip list khy ===
pip list 2>NUL | findstr /i khy
echo === local .khy size ===
dir /s C:\Users\25789\.khy 2>NUL
echo === check pip cache for khy ===
dir /s /b C:\Users\25789\AppData\Local\pip\cache\*khy* 2>NUL || echo "no pip cache for khy"
echo === check any khy in temp ===
dir /s /b C:\Users\25789\AppData\Local\Temp\*khy* 2>NUL || echo "no khy in temp"

echo === rar file ===
dir D:\Python312\Lib\site-packages\khy_os.rar
echo === garbled docs ===
dir /s /b D:\Python312\Lib\site-packages\khy_os\bundled\docs\~-ides\ 2>NUL
echo === garbled software ===
dir /s /b D:\Python312\Lib\site-packages\khy_os\bundled\software\~-yquant\ 2>NUL

echo === rar file ===
dir D:\Python312\Lib\site-packages\khy_os.rar
echo === garbled docs ===
dir /s /b D:\Python312\Lib\site-packages\khy_os\bundled\docs\~-ides\ 2>NUL
echo === garbled software ===
dir /s /b D:\Python312\Lib\site-packages\khy_os\bundled\software\~-yquant\ 2>NUL

$sp = "D:\Python312\Lib\site-packages"
Write-Host "=== khy_os.rar ==="
if (Test-Path "$sp\khy_os.rar") { "STILL EXISTS" } else { "已删除" }

Write-Host "=== Tilde-prefixed in docs ==="
$tildeDocs = Get-ChildItem "$sp\khy_os\bundled\docs" -Directory | Where-Object { $_.Name -like '~*' }
if ($tildeDocs) { $tildeDocs | ForEach-Object { $_.FullName } } else { "无残留" }

Write-Host "=== Tilde-prefixed in software ==="
$tildeSw = Get-ChildItem "$sp\khy_os\bundled\software" -Directory | Where-Object { $_.Name -like '~*' }
if ($tildeSw) { $tildeSw | ForEach-Object { $_.FullName } } else { "无残留" }

Write-Host "=== Final software dirs ==="
Get-ChildItem "$sp\khy_os\bundled\software" -Directory | Select-Object Name

$src = "D:\Python312\Lib\site-packages\khy_os"
$dest = "D:\HuaweiMoveData\Users\25789\Desktop\khy_os_backup.zip"
$excludes = @("*.db", "*.db-*", "*.lock")
if (Test-Path $dest) { Remove-Item $dest -Force }
$files = Get-ChildItem $src -Recurse -File | Where-Object {
    $exclude = $false
    foreach ($e in $excludes) { if ($_.Name -like $e) { $exclude = $true; break } }
    -not $exclude
}
Compress-Archive -Path ($files.DirectoryName | Select-Object -Unique) -DestinationPath $dest -CompressionLevel Fastest -Force
Write-Host "Done: $dest"
$item = Get-Item $dest
Write-Host "Size:" ($item.Length / 1MB).ToString("F1") "MB"

$src = "D:\Python312\Lib\site-packages\khy_os"
$dest = "D:\HuaweiMoveData\Users\25789\Desktop\khy_os_backup.zip"
$locked = @("bundled.zip", "sessions.db")
if (Test-Path $dest) { Remove-Item $dest -Force }
Write-Host "Excluding locked files..."
Get-ChildItem $src -Recurse -File | Where-Object {
    $skip = $false
    foreach ($l in $locked) { if ($_.Name -eq $l) { $skip = $true; break } }
    -not $skip
} | Compress-Archive -DestinationPath $dest -CompressionLevel Fastest -Force
Write-Host "Done"
$item = Get-Item $dest
Write-Host "Size:" ($item.Length / 1MB).ToString("F1") "MB"
